-- 通知测试数据
-- 系统公告、活动通知、更新通知等

INSERT INTO `notice` (`id`, `title`, `context`, `type`, `create_time`, `create_by`, `update_time`, `update_by`) VALUES
(1, '社区服务升级公告', '<p>亲爱的用户们：</p><p>为了提供更好的服务体验，我们将于2026年4月10日凌晨2:00-4:00进行系统维护升级。期间可能会出现服务不稳定的情况，敬请谅解。</p><p>升级内容：</p><p>1. 优化文章浏览性能</p><p>2. 新增用户私信功能</p><p>3. 修复已知bug</p><p>感谢您的理解与支持！</p>', '系统公告', '2026-04-05 10:00:00', 'admin', '2026-04-05 10:00:00', 'admin'),

(2, '春季技术征文活动', '<p>🌸 春季技术征文活动开始啦！</p><p>活动时间：2026年4月1日-4月30日</p><p>活动规则：</p><p>1. 发布原创技术文章即可参与</p><p>2. 文章需包含代码示例或实战经验</p><p>3. 活动期间发布文章数量前3名将获得丰厚奖励</p><p>奖品设置：</p><p>🥇 第一名：机械键盘 + 定制T恤</p><p>🥈 第二名：无线鼠标 + 定制水杯</p><p>🥉 第三名：定制T恤 + 纪念U盘</p><p>快来参与吧！</p>', '活动通知', '2026-04-01 09:00:00', '运营部', '2026-04-01 09:00:00', '运营部'),

(3, '新功能上线：文章分类', '<p>好消息！文章分类功能正式上线啦！🎉</p><p>现在发布文章时可以选择对应的分类标签，让文章更容易被发现！</p><p>支持分类：</p><p>• Java、Python、Vue、Spring Boot等编程语言</p><p>• 人工智能、机器学习等技术领域</p><p>• 算法、设计模式等编程基础</p><p>• 测试、运维等工程实践</p><p>快来试试新功能吧！</p>', '功能更新', '2026-04-03 14:00:00', '技术部', '2026-04-03 14:00:00', '技术部'),

(4, '社区公约更新提醒', '<p>为了营造更好的交流环境，我们更新了社区公约，请各位用户仔细阅读。</p><p>主要更新内容：</p><p>1. 规范文章标题和内容格式</p><p>2. 禁止发布重复内容</p><p>3. 尊重他人知识产权</p><p>4. 友善交流，理性讨论</p><p>违反公约的用户将根据情节严重程度给予警告、禁言或封禁处理。</p><p>详细内容请查看社区公约页面。</p>', '规则提醒', '2026-04-04 11:30:00', '管理组', '2026-04-04 11:30:00', '管理组'),

(5, '周报：社区数据统计', '<p>📊 上周社区数据统计（2026.03.28-04.03）</p><p>新增用户：56人</p><p>新增文章：34篇</p><p>文章浏览量：12,580次</p><p>活跃用户：89人</p><p>热门文章TOP3：</p><p>1. 机器学习基础入门 - 526次浏览</p><p>2. Git版本控制最佳实践 - 456次浏览</p><p>3. 算法与数据结构精讲 - 412次浏览</p><p>感谢大家的积极参与！</p>', '数据统计', '2026-04-04 16:00:00', '运营部', '2026-04-04 16:00:00', '运营部'),

(6, '举报功能优化通知', '<p>感谢大家对社区内容质量的监督！</p><p>我们优化了举报功能：</p><p>1. 增加了更多举报理由选项</p><p>2. 举报后可以查看处理进度</p><p>3. 管理员会在24小时内处理举报</p><p>让我们共同维护一个健康、友好的交流环境！</p>', '功能优化', '2026-04-05 09:00:00', '管理组', '2026-04-05 09:00:00', '管理组'),

(7, '账号安全提醒', '<p>🔒 账号安全提醒</p><p>近期发现部分用户账号存在安全风险，请各位用户注意：</p><p>1. 定期修改密码，使用强密码</p><p>2. 不要轻易透露账号信息</p><p>3. 警惕钓鱼网站和虚假链接</p><p>4. 建议开启二次验证</p><p>如发现账号异常，请及时联系客服或通过安全设置进行保护。</p>', '安全提醒', '2026-04-05 08:30:00', '安全中心', '2026-04-05 08:30:00', '安全中心'),

(8, '技术问答专区开放', '<p>💡 技术问答专区正式开放！</p><p>在这里你可以：</p><p>• 提出技术问题，获得社区解答</p><p>• 分享你的知识和经验</p><p>• 查看他人的问答，共同学习</p><p>提问建议：</p><p>1. 问题描述要清晰完整</p><p>2. 提供代码示例或错误信息</p><p>3. 标注相关技术标签</p><p>让我们一起进步，共同成长！</p>', '功能上线', '2026-04-02 15:00:00', '技术部', '2026-04-02 15:00:00', '技术部'),

(9, '用户积分系统上线', '<p>🎁 用户积分系统正式上线！</p><p>获得积分方式：</p><p>• 发布文章：+10积分</p><p>• 文章被收藏：+5积分</p><p>• 发表评论：+2积分</p><p>• 每日登录：+1积分</p><p>积分用途：</p><p>• 兑换社区周边礼品</p><p>• 提升用户等级</p><p>• 解锁特殊权限</p><p>快来赚取积分吧！</p>', '功能上线', '2026-04-03 10:00:00', '运营部', '2026-04-03 10:00:00', '运营部'),

(10, '五一劳动节放假通知', '<p>🎉 五一劳动节放假通知</p><p>放假时间：2026年5月1日-5月5日</p><p>放假期间：</p><p>1. 社区正常开放，大家可以正常使用</p><p>2. 客服服务时间调整为每日9:00-18:00</p><p>3. 工单处理可能会有延迟，敬请谅解</p><p>祝大家劳动节快乐，享受假期！</p>', '节日通知', '2026-04-20 14:00:00', '管理组', '2026-04-20 14:00:00', '管理组');